import React, { useState, useEffect } from 'react';
import axios from 'axios';

const API = "http://localhost:3000/api";

function App() {
  const [user, setUser] = useState(null);
  const [students, setStudents] = useState([]);
  const [activeExam, setActiveExam] = useState("bil1");
  const [search, setSearch] = useState("");
  const [form, setForm] = useState({ id: "", pass: "" });

  useEffect(() => { if (user?.role === 'admin') loadData(); }, [user]);
  const loadData = () => axios.get(`${API}/students`).then(res => setStudents(res.data));

  const calculateResults = (examData, subjects) => {
    let total = 0;
    subjects.forEach(sub => total += (Number(examData[sub]) || 0));
    let percentage = (total / (subjects.length * 100)) * 100;
    return { total, percentage: percentage.toFixed(1) };
  };

  if (!user) {
    return (
      <div style={st.loginBg}>
        <div style={st.card}>
          <h2 style={{color: '#1a73e8'}}>UOB PORTAL 2026</h2>
          <input placeholder="ID (admin / BCS/...)" style={st.in} onChange={e => setForm({...form, id: e.target.value})} />
          <input type="password" placeholder="Password" style={st.in} onChange={e => setForm({...form, pass: e.target.value})} />
          <button onClick={() => axios.post(`${API}/login`, {id: form.id, password: form.pass}).then(res => setUser(res.data)).catch(()=>alert("Khalad!"))} style={st.loginBtn}>LOGIN</button>
        </div>
      </div>
    );
  }

  return (
    <div style={{display: 'flex', height: '100vh', fontFamily: 'Segoe UI, sans-serif'}}>
      {/* SIDEBAR */}
      <div style={st.sidebar}>
        <h2 style={{textAlign: 'center', fontSize: '18px'}}>UOB SYSTEM</h2>
        {["bil1", "midterm", "bil3", "final"].map(ex => (
          <button key={ex} onClick={() => setActiveExam(ex)} style={activeExam === ex ? st.actM : st.mBtn}>{ex.toUpperCase()}</button>
        ))}
        <button onClick={() => setUser(null)} style={st.outBtn}>Logout</button>
      </div>

      {/* MAIN CONTENT */}
      <div style={{flex: 1, padding: '30px', background: '#f8f9fa', overflowY: 'auto'}}>
        {user.role === 'admin' ? (
          <div>
            <div style={{display: 'flex', justifyContent: 'space-between', marginBottom: '20px'}}>
              <h2>Maamulka: {activeExam.toUpperCase()}</h2>
              <input placeholder="🔍 Raadi ID Arday..." style={st.searchIn} onChange={e => setSearch(e.target.value)} />
            </div>
            {students.filter(s => s.id.includes(search)).map(s => (
              <div key={s.id} style={st.adminRow}>
                <div style={{display: 'flex', justifyContent: 'space-between', borderBottom: '1px solid #eee', paddingBottom: '10px'}}>
                  <b>{s.magaca} ({s.id}) - {s.fasalka}</b>
                  <b style={{color: '#1a73e8'}}>Total: {calculateResults(s.exams[activeExam], subjectsByClass[s.fasalka] || []).total}</b>
                </div>
                <div style={{display: 'flex', flexWrap: 'wrap', gap: '15px', marginTop: '10px'}}>
                  {(subjectsByClass[s.fasalka] || []).map(sub => (
                    <div key={sub}>
                      <label style={{fontSize: '11px'}}>{sub}:</label><br/>
                      <input type="number" defaultValue={s.exams[activeExam][sub]} style={st.miniIn}
                        onBlur={e => axios.put(`${API}/update-grade`, {id: s.id, examType: activeExam, subject: sub, grade: e.target.value}).then(loadData)} />
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div style={st.studentCard}>
            <h2 style={{borderBottom: '2px solid #1a73e8', paddingBottom: '10px'}}>Warbixinta Natiijada</h2>
            <div style={{margin: '20px 0', fontSize: '18px'}}>
               ID: <b>{user.id}</b> | Fasalka: <b>{user.fasalka}</b> | Imtixaan: <b>{activeExam.toUpperCase()}</b>
            </div>
            <table style={st.table}>
              <thead>
                <tr style={{background: '#1a73e8', color: 'white'}}>
                  <th style={st.th}>Maadada</th><th style={st.th}>Dhibicda</th><th style={st.th}>Natiijada</th>
                </tr>
              </thead>
              <tbody>
                {user.subjects.map(sub => {
                  const score = user.exams[activeExam][sub] || 0;
                  return (
                    <tr key={sub} style={{borderBottom: '1px solid #ddd'}}>
                      <td style={st.td}>{sub}</td>
                      <td style={st.td}>{score}</td>
                      <td style={{...st.td, color: score >= 50 ? 'green' : 'red', fontWeight: 'bold'}}>
                        {score >= 50 ? "✓ Sax (Pass)" : "✗ Qalad (Fail)"}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
            <div style={st.resultSummary}>
              <h3>Total-ka: {calculateResults(user.exams[activeExam], user.subjects).total}</h3>
              <h3>Boqolleyda: {calculateResults(user.exams[activeExam], user.subjects).percentage}%</h3>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

const subjectsByClass = { 
  "1aad": ["Soomaali", "Xisaab", "Carabi", "English"], 
  "9aad": ["Tarbiy", "Carbi", "English", "Geo", "ICT", "Hist", "Phy", "Soom", "Math", "Bio", "Chem"],
  "12aad": ["Tarbiyo", "Carbi", "English", "Geo", "ICT", "Hist", "Phy", "Soom", "Math", "Bio", "Chem"]
};

const st = {
  loginBg: { height: '100vh', display: 'flex', justifyContent: 'center', alignItems: 'center', background: '#eef2f3' },
  card: { background: 'white', padding: '40px', borderRadius: '20px', boxShadow: '0 8px 30px rgba(0,0,0,0.1)', textAlign: 'center' },
  in: { display: 'block', width: '300px', padding: '15px', margin: '15px 0', borderRadius: '10px', border: '1px solid #ddd' },
  loginBtn: { width: '100%', padding: '15px', background: '#1a73e8', color: 'white', border: 'none', borderRadius: '10px', cursor: 'pointer', fontWeight: 'bold' },
  sidebar: { width: '250px', background: '#1c2833', color: 'white', padding: '20px', display: 'flex', flexDirection: 'column' },
  mBtn: { padding: '15px', background: 'transparent', color: '#abb2b9', border: 'none', textAlign: 'left', cursor: 'pointer', borderBottom: '1px solid #2c3e50' },
  actM: { padding: '15px', background: '#1a73e8', color: 'white', border: 'none', textAlign: 'left', borderRadius: '8px' },
  outBtn: { marginTop: 'auto', background: '#c0392b', color: 'white', padding: '12px', border: 'none', borderRadius: '8px', cursor: 'pointer' },
